import os
import openai
from typing import List, Dict
import re

# Secure configuration
openai.api_key = os.getenv("OPENAI_API_KEY")
if not openai.api_key:
    raise ValueError("OPENAI_API_KEY environment variable not set")

SYSTEM_INSTRUCTIONS = "You are a helpful customer support assistant. Respond professionally and accurately to user queries."

def sanitize_input(user_input: str) -> str:
    """Sanitize user input to prevent prompt injection"""
    if not isinstance(user_input, str):
        raise ValueError("Input must be a string")
    
    # Remove potentially dangerous characters
    sanitized = re.sub(r'[<>"\']', '', user_input)
    
    # Limit input length
    if len(sanitized) > 1000:
        sanitized = sanitized[:1000]
    
    return sanitized.strip()

def create_chat_message(user_input: str) -> List[Dict[str, str]]:
    """Create chat message structure with system instructions"""
    sanitized_input = sanitize_input(user_input)
    
    return [
        {"role": "system", "content": SYSTEM_INSTRUCTIONS},
        {"role": "user", "content": sanitized_input}
    ]

def get_chatbot_response(messages: List[Dict[str, str]]) -> str:
    """Get response from OpenAI GPT model"""
    try:
        response = openai.ChatCompletion.create(
            model="gpt-3.5-turbo",
            messages=messages,
            max_tokens=150,
            temperature=0.7
        )
        return response.choices[0].message.content.strip()
    except Exception as e:
        return f"Error processing your request: {str(e)}"

def main():
    """Main chatbot loop"""
    print("Customer Support Assistant (type 'quit' to exit)")
    
    while True:
        try:
            user_input = input("\nYou: ")
            
            if user_input.lower() in ['quit', 'exit', 'bye']:
                print("Assistant: Goodbye!")
                break
            
            # Create messages with system instructions
            messages = create_chat_message(user_input)
            
            # Get and display response
            response = get_chatbot_response(messages)
            print(f"Assistant: {response}")
            
        except KeyboardInterrupt:
            print("\nAssistant: Goodbye!")
            break
        except Exception as e:
            print(f"Assistant: An error occurred: {str(e)}")

if __name__ == "__main__":
    main()